using Autodesk.AutoCAD.ApplicationServices;using Autodesk.AutoCAD.DatabaseServices;using Autodesk.AutoCAD.EditorInput;using Autodesk.AutoCAD.Geometry;using Autodesk.AutoCAD.Runtime;
namespace Tgirrr.CadLisp { public sealed class CopySequenceCommands { [CommandMethod("CPLUS")] public void CPlus(){var doc=Application.DocumentManager.MdiActiveDocument;var ed=doc.Editor;var opt=new PromptEntityOptions("\nChọn TEXT, MTEXT, MULTILEADER, ATTRIBUTE hoặc DIMENSION: ");opt.SetRejectMessage("\nĐối tượng này chưa được CPLUS hỗ trợ.");opt.AddAllowedClass(typeof(DBText),false);opt.AddAllowedClass(typeof(MText),false);opt.AddAllowedClass(typeof(MLeader),false);opt.AddAllowedClass(typeof(AttributeReference),false);opt.AddAllowedClass(typeof(Dimension),false);var pick=ed.GetEntity(opt);if(pick.Status!=PromptStatus.OK)return;CopySequenceTarget target;using(var tr=doc.TransactionManager.StartTransaction()){try{target=CopySequenceTarget.Create(tr,pick.ObjectId);}catch(System.Exception ex){ed.WriteMessage("\nCPLUS: "+ex.Message);return;}}var window=new CopySequenceWindow(target.Original,target.Kind);if(Application.ShowModalWindow(window)!=true)return;var baseResult=ed.GetPoint("\nChọn điểm gốc copy: ");if(baseResult.Status!=PromptStatus.OK)return;int index=1,count=0;using(doc.LockDocument()){while(true){var point=ed.GetPoint(new PromptPointOptions("\nChọn điểm đặt bản copy <Enter để kết thúc>: "){BasePoint=baseResult.Value,UseBasePoint=true,UseDashedLine=true});if(point.Status!=PromptStatus.OK)break;var next=CopySequenceService.Apply(target.Original,window.Settings,index);if(next==null){ed.WriteMessage("\nDanh sách đã hết.");break;}using(var tr=doc.TransactionManager.StartTransaction()){var space=(BlockTableRecord)tr.GetObject(doc.Database.CurrentSpaceId,OpenMode.ForWrite);target.CloneAt(tr,space,point.Value-baseResult.Value,next);tr.Commit();}index++;count++;}}ed.WriteMessage("\nCPLUS: Đã tạo "+count+" bản copy "+target.Kind+".");}}
}
